// Solo los riegos de la planta con id 1
const { data } = await supabase
  .from('riegos')
  .select('*')
  .eq('planta_id', 1);

console.log('Esta planta se ha regado ' + data.length + ' veces');

// Solo las plantas que llevan más de 3 días sin agua
const { data: secas } = await supabase
  .from('plantas')
  .select('*')
  .gt('dias_sin_agua', 3);

// Los 3 equipos con más puntos
const { data } = await supabase
  .from('equipos')
  .select('*')
  .order('puntos', { ascending: false })
  .limit(3);

for (const equipo of data) {
  console.log(equipo.nombre + ': ' + equipo.puntos + ' pts');
}

// Opción sencilla: traer y contar con .length
const { data } = await supabase.from('plantas').select('*');
console.log('Tengo ' + data.length + ' plantas');

// Opción eficiente: contar sin traer las filas
const { count } = await supabase
  .from('plantas')
  .select('*', { count: 'exact', head: true });
console.log('Total: ' + count);

const { data } = await supabase.from('notas').select('*');

// Total
let suma = 0;
for (const fila of data) {
  suma += fila.valor;
}

// Media (¡cuidado con dividir entre cero!)
const media = data.length > 0 ? suma / data.length : 0;
console.log('Media: ' + media.toFixed(2));

// Porcentaje de aprobados (>= 5)
const aprobados = data.filter(f => f.valor >= 5).length;
const porcentaje = data.length > 0
  ? (aprobados / data.length) * 100
  : 0;
console.log('Aprobados: ' + porcentaje.toFixed(0) + '%');

async function pintarPanel() {
  const { data } = await supabase.from('plantas').select('*');

  const total = data.length;
  const secas = data.filter(p => p.dias_sin_agua > 3).length;

  document.querySelector('#total').textContent = total;
  document.querySelector('#secas').textContent = secas;
}

pintarPanel();

